import{_ as a,o as e,c as n,a0 as r}from"./chunks/framework.D7EjqxMK.js";const c=JSON.parse('{"title":"端到端 Agent 训练","description":"","frontmatter":{},"headers":[],"relativePath":"06-agent/05_前沿趋势/02_端到端 Agent 训练.md","filePath":"06-agent/05_前沿趋势/02_端到端 Agent 训练.md"}'),s={name:"06-agent/05_前沿趋势/02_端到端 Agent 训练.md"};function d(o,t,l,i,h,g){return e(),n("div",null,[...t[0]||(t[0]=[r(`<h1 id="端到端-agent-训练" tabindex="-1">端到端 Agent 训练 <a class="header-anchor" href="#端到端-agent-训练" aria-label="Permalink to &quot;端到端 Agent 训练&quot;">​</a></h1><blockquote><p><strong>在知识图谱中的位置</strong>：模块五 · 05_前沿趋势 · 第 2 节 <strong>难度</strong>：⭐⭐⭐ | <strong>前置知识</strong>：RLHF/RL</p></blockquote><hr><h2 id="_1-概述" tabindex="-1">1. 概述 <a class="header-anchor" href="#_1-概述" aria-label="Permalink to &quot;1. 概述&quot;">​</a></h2><p><strong>端到端 Agent 训练</strong>是指直接训练 LLM 成为 Agent，而非通过 Prompt Engineering。代表技术：RLHF → GRPO → 端到端 Agent 训练。</p><hr><h2 id="_2-技术演进" tabindex="-1">2. 技术演进 <a class="header-anchor" href="#_2-技术演进" aria-label="Permalink to &quot;2. 技术演进&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>监督微调 (SFT) → RLHF → DPO → GRPO → 端到端 Agent 训练</span></span>
<span class="line"><span>                人工偏好  直接偏好  小组奖励   环境反馈</span></span></code></pre></div><h3 id="关键突破" tabindex="-1">关键突破 <a class="header-anchor" href="#关键突破" aria-label="Permalink to &quot;关键突破&quot;">​</a></h3><table tabindex="0"><thead><tr><th>技术</th><th>时间</th><th>核心</th></tr></thead><tbody><tr><td><strong>RLHF</strong></td><td>2022</td><td>人类偏好训练</td></tr><tr><td><strong>DPO</strong></td><td>2023</td><td>直接偏好优化</td></tr><tr><td><strong>GRPO</strong></td><td>2024</td><td>Group Relative Policy Optimization</td></tr><tr><td><strong>RLVR</strong></td><td>2024</td><td>环境反馈训练</td></tr><tr><td><strong>端到端 Agent</strong></td><td>2025</td><td>直接在环境中训练 Agent</td></tr></tbody></table><hr><h2 id="_3-技术原理" tabindex="-1">3. 技术原理 <a class="header-anchor" href="#_3-技术原理" aria-label="Permalink to &quot;3. 技术原理&quot;">​</a></h2><h3 id="_3-1-rlvr-框架" tabindex="-1">3.1 RLVR 框架 <a class="header-anchor" href="#_3-1-rlvr-框架" aria-label="Permalink to &quot;3.1 RLVR 框架&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>环境（Agent 执行环境）</span></span>
<span class="line"><span>    ↓ reward</span></span>
<span class="line"><span>训练数据（状态 → 动作 → reward）</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>RL 训练 → 优化 Agent 策略 → 更好的 Agent</span></span></code></pre></div><h3 id="_3-2-端到端-agent-训练流程" tabindex="-1">3.2 端到端 Agent 训练流程 <a class="header-anchor" href="#_3-2-端到端-agent-训练流程" aria-label="Permalink to &quot;3.2 端到端 Agent 训练流程&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. 定义 Agent 环境（工具/奖励函数）</span></span>
<span class="line"><span>2. 收集 Agent 执行轨迹</span></span>
<span class="line"><span>3. 用 GRPO/RLVR 训练模型</span></span>
<span class="line"><span>4. 模型学会自主规划 + 工具调用</span></span>
<span class="line"><span>5. 迭代训练直到收敛</span></span></code></pre></div><hr><h2 id="_4-影响" tabindex="-1">4. 影响 <a class="header-anchor" href="#_4-影响" aria-label="Permalink to &quot;4. 影响&quot;">​</a></h2><h3 id="_4-1-对-agent-开发的影响" tabindex="-1">4.1 对 Agent 开发的影响 <a class="header-anchor" href="#_4-1-对-agent-开发的影响" aria-label="Permalink to &quot;4.1 对 Agent 开发的影响&quot;">​</a></h3><table tabindex="0"><thead><tr><th>变化</th><th>说明</th></tr></thead><tbody><tr><td><strong>Prompt Engineering 减少</strong></td><td>模型学会自主推理</td></tr><tr><td><strong>框架简化</strong></td><td>Agent 能力内嵌到模型</td></tr><tr><td><strong>训练成本上升</strong></td><td>需要 RL 基础设施</td></tr><tr><td><strong>个性化 Agent</strong></td><td>可为特定任务微调</td></tr></tbody></table><h3 id="_4-2-代表项目" tabindex="-1">4.2 代表项目 <a class="header-anchor" href="#_4-2-代表项目" aria-label="Permalink to &quot;4.2 代表项目&quot;">​</a></h3><table tabindex="0"><thead><tr><th>项目</th><th>描述</th></tr></thead><tbody><tr><td><strong>DeepSeek-R1</strong></td><td>用 GRPO 训练的推理 Agent</td></tr><tr><td><strong>Qwen-Agent</strong></td><td>阿里端到端 Agent</td></tr><tr><td><strong>Gemini 2.0</strong></td><td>Google 原生多模态 Agent</td></tr><tr><td><strong>Claude 3.5</strong></td><td>Anthropic RL 训练</td></tr></tbody></table><hr><h2 id="_5-参考资料" tabindex="-1">5. 参考资料 <a class="header-anchor" href="#_5-参考资料" aria-label="Permalink to &quot;5. 参考资料&quot;">​</a></h2><ul><li><a href="https://arxiv.org/abs/2402.03300" target="_blank" rel="noreferrer">GRPO 论文</a></li><li><a href="https://arxiv.org/abs/2501.12948" target="_blank" rel="noreferrer">DeepSeek-R1 技术报告</a></li><li><a href="https://arxiv.org/abs/2601.02749" target="_blank" rel="noreferrer">端到端 Agent 训练综述</a></li></ul>`,25)])])}const b=a(s,[["render",d]]);export{c as __pageData,b as default};
